const crypto = require('crypto');
const canonicalize = (value) => {
  if (value === null || typeof value !== 'object') return JSON.stringify(value);
  if (Array.isArray(value)) return `[${value.map(canonicalize).join(',')}]`;
  return `{${Object.keys(value).sort().filter((key) => value[key] !== undefined).map((key) => `${JSON.stringify(key)}:${canonicalize(value[key])}`).join(',')}}`;
};
let envelope = $json.runtime_event;
if (!envelope) {
  const executionId = String($json.execution?.id ?? $execution.id);
  envelope = { schema_version: '0.2.0', adapter: { adapter_id: 'alphonse.n8n.runtime', adapter_version: '0.2.0' }, workflow_id: $env.ALPHONSE_WORKFLOW_ID, revision_id: $env.ALPHONSE_REVISION_ID, external_execution_id: `n8n-${executionId}`, event_id: `n8n-${executionId}-failed`, event_sequence: 1, lifecycle_claim: 'failed', correlation_id: `n8n-${executionId}`, idempotency_key: `n8n-${executionId}:1`, occurred_at: new Date().toISOString(), payload: { digest: `sha256:${crypto.createHash('sha256').update(canonicalize($json)).digest('hex')}`, reference: null } };
}
const keyId = $env.ALPHONSE_RUNTIME_ADAPTER_KEY_ID;
const signedAt = new Date().toISOString();
const bytes = ['alphonse-runtime-event-hmac-v1', keyId, signedAt, canonicalize(envelope)].join('\n');
const signature = `hmac-sha256:${crypto.createHmac('sha256', $env.ALPHONSE_RUNTIME_ADAPTER_SECRET).update(bytes, 'utf8').digest('hex')}`;
return [{ json: { envelope, authentication: { key_id: keyId, signed_at: signedAt, signature } } }];
